'use server'

import { createClient } from '@/lib/supabase/server'
import { createAuthUser, updateAuthUserMetadata } from '@/lib/supabase/admin'
import { getCurrentUser } from '@/lib/actions/auth-actions'
import type { Employee } from '@/lib/types/database'

export interface ActionResult<T = void> {
  success: boolean
  data?: T
  error?: string
}

// Г"?Г"?Г"? Employee with branch name (joined) Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export interface EmployeeWithBranch extends Employee {
  branch_name?: string | null
}

// Г"?Г"?Г"? Create employee input Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export interface CreateEmployeeInput {
  employee_code: string
  full_name: string
  email: string
  password: string
  phone?: string | null
  position: Employee['position']
  role: Employee['role']
  branch_id?: string | null
  rate_per_session: number
  sub_rate?: number
  has_labor_contract: boolean
  dependent_count: number
}

// Г"?Г"?Г"? Get employees Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export async function getEmployees(
  branchId?: string
): Promise<ActionResult<EmployeeWithBranch[]>> {
  try {
    const user = await getCurrentUser()
    if (!user) return { success: false, error: 'ChТ°a О`ОЯng nhаз-p.' }

    const canView = user.role === 'admin' || user.role === 'branch_manager'
    if (!canView) return { success: false, error: 'Bазнn khA'ng cA3 quyап?n xem nhAЫn viAжn.' }

    const supabase = await createClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sb = supabase as any

    let query = sb.from('employees').select('*, branches(name)').order('full_name')

    if (user.role === 'branch_manager' && user.branch_id) {
      query = query.eq('branch_id', user.branch_id)
    } else if (branchId) {
      query = query.eq('branch_id', branchId)
    }

    const { data, error } = await query
    if (error) throw error

    const employees: EmployeeWithBranch[] = ((data as unknown[]) ?? []).map((emp) => {
      const e = emp as Employee & { branches: { name: string } | null }
      const { branches, ...rest } = e
      return { ...rest, branch_name: branches?.name ?? null }
    })

    return { success: true, data: employees }
  } catch (err) {
    console.error('[getEmployees]', err)
    return { success: false, error: 'KhA'ng thапЯ tазЬi danh sAнch nhAЫn viAжn.' }
  }
}

// Г"?Г"?Г"? Get employee by ID Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export async function getEmployeeById(
  id: string
): Promise<ActionResult<EmployeeWithBranch>> {
  try {
    const user = await getCurrentUser()
    if (!user) return { success: false, error: 'ChТ°a О`ОЯng nhаз-p.' }

    const supabase = await createClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sb = supabase as any
    const { data, error } = await sb
      .from('employees')
      .select('*, branches(name)')
      .eq('id', id)
      .maybeSingle()

    if (error) throw error
    if (!data) return { success: false, error: 'KhA'ng tAкm thазЭy nhAЫn viAжn.' }

    const emp = data as Employee & { branches: { name: string } | null }

    if (user.role === 'branch_manager' && emp.branch_id !== user.branch_id) {
      return { success: false, error: 'Bазнn khA'ng cA3 quyап?n xem nhAЫn viAжn nA y.' }
    }

    const { branches, ...rest } = emp
    return { success: true, data: { ...rest, branch_name: emp.branches?.name ?? null } }
  } catch (err) {
    console.error('[getEmployeeById]', err)
    return { success: false, error: 'KhA'ng thапЯ tазЬi thA'ng tin nhAЫn viAжn.' }
  }
}

// Г"?Г"?Г"? Create employee Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export async function createEmployee(
  input: CreateEmployeeInput
): Promise<ActionResult<Employee>> {
  try {
    const user = await getCurrentUser()
    if (!user) return { success: false, error: 'ChТ°a О`ОЯng nhаз-p.' }

    const canCreate = user.role === 'admin' || user.role === 'branch_manager'
    if (!canCreate) return { success: false, error: 'Bазнn khA'ng cA3 quyап?n tазнo nhAЫn viAжn.' }

    const branchId = user.role === 'branch_manager' ? user.branch_id : (input.branch_id ?? null)

    // 1. Create auth user with role + branch in app_metadata
    const authUser = await createAuthUser({
      email: input.email,
      password: input.password,
      role: input.role,
      branchId: branchId ?? undefined,
    })

    // 2. Insert employee record (id = auth.users.id)
    const supabase = await createClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sb = supabase as any

    const { data: employee, error } = await sb.from('employees').insert({
      id: authUser.id,
      employee_code: input.employee_code,
      full_name: input.full_name,
      email: input.email,
      phone: input.phone ?? null,
      position: input.position,
      role: input.role,
      branch_id: branchId,
      rate_per_session: input.rate_per_session,
      sub_rate: input.sub_rate ?? 0,
      has_labor_contract: input.has_labor_contract,
      dependent_count: input.dependent_count,
      is_active: true,
      join_date: new Date().toISOString().split('T')[0],
    }).select().single()

    if (error) throw error
    return { success: true, data: employee as Employee }
  } catch (err: unknown) {
    console.error('[createEmployee]', err)
    const msg = err instanceof Error ? err.message : ''
    if (msg.includes('already registered') || msg.includes('already been registered')) {
      return { success: false, error: 'Email О`AЬ tап"n tазнi trong hап╪ thап`ng.' }
    }
    return { success: false, error: 'KhA'ng thапЯ tазнo nhAЫn viAжn.' }
  }
}

// Г"?Г"?Г"? Update employee Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export async function updateEmployee(
  id: string,
  data: Record<string, unknown>
): Promise<ActionResult<Employee>> {
  try {
    const user = await getCurrentUser()
    if (!user) return { success: false, error: 'ChТ°a О`ОЯng nhаз-p.' }

    const canEdit = user.role === 'admin' || user.role === 'branch_manager'
    if (!canEdit) return { success: false, error: 'Bазнn khA'ng cA3 quyап?n sап-a nhAЫn viAжn.' }

    const supabase = await createClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sb = supabase as any

    // Branch manager scope check
    if (user.role === 'branch_manager') {
      const { data: existing } = await sb
        .from('employees').select('branch_id').eq('id', id).maybeSingle()
      const e = existing as { branch_id: string | null } | null
      if (e?.branch_id !== user.branch_id) {
        return { success: false, error: 'Bазнn khA'ng cA3 quyап?n sап-a nhAЫn viAжn nA y.' }
      }
    }

    const { data: employee, error } = await sb
      .from('employees').update(data).eq('id', id).select().single()

    if (error) throw error

    // Sync role + branch_id to app_metadata if changed
    if (data.role !== undefined || data.branch_id !== undefined) {
      await updateAuthUserMetadata(id, {
        role: data.role as string | undefined,
        branchId: data.branch_id as string | undefined,
      })
    }

    return { success: true, data: employee as Employee }
  } catch (err) {
    console.error('[updateEmployee]', err)
    return { success: false, error: 'KhA'ng thапЯ cаз-p nhаз-t nhAЫn viAжn.' }
  }
}

