import { redirect } from 'next/navigation'
import { createClient } from '@/lib/supabase/server'

// Г"?Г"?Г"? Login Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export interface LoginResult {
  success: boolean
  error?: string
}

export async function loginAction(
  email: string,
  password: string
): Promise<LoginResult> {
  const supabase = await createClient()

  const { data, error } = await supabase.auth.signInWithPassword({
    email: email.trim().toLowerCase(),
    password,
  })

  if (error) {
    // Return user-friendly Vietnamese messages
    if (error.message.includes('Invalid login credentials')) {
      return { success: false, error: 'Email hoаз·c mаз-t khазcu khA'ng О`Aзng.' }
    }
    if (error.message.includes('Email not confirmed')) {
      return { success: false, error: 'Email chТ°a О`Т°апЬc xAнc nhаз-n.' }
    }
    return { success: false, error: 'О?ОЯng nhаз-p thазЭt bазнi. Vui lA¤ng thап- lазнi.' }
  }

  if (!data.user) {
    return { success: false, error: 'KhA'ng tAкm thазЭy tA i khoазЬn.' }
  }

  // Verify employee record exists and is active
  type EmployeeRow = { id: string; is_active: boolean; role: string }
  const empResult = await supabase
    .from('employees')
    .select('id, is_active, role')
    .eq('id', data.user.id)
    .maybeSingle()

  const employee = empResult.data as EmployeeRow | null

  if (empResult.error || !employee) {
    await supabase.auth.signOut()
    return { success: false, error: 'TA i khoазЬn nhAЫn viAжn khA'ng tап"n tазнi.' }
  }

  if (!employee.is_active) {
    await supabase.auth.signOut()
    return { success: false, error: 'TA i khoазЬn О`AЬ bап< vA' hiап╪u hA3a.' }
  }

  redirect('/dashboard')
}

// Г"?Г"?Г"? Logout Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export async function logoutAction(): Promise<void> {
  const supabase = await createClient()
