  redirect('/login')
}

// Г"?Г"?Г"? Reset Password Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export interface ResetPasswordResult {
  success: boolean
  error?: string
}

export async function resetPasswordAction(
  email: string
): Promise<ResetPasswordResult> {
  const supabase = await createClient()

  const { error } = await supabase.auth.resetPasswordForEmail(
    email.trim().toLowerCase(),
    {
      redirectTo: `${process.env.NEXT_PUBLIC_APP_URL}/reset-password/update`,
    }
  )

  if (error) {
    return { success: false, error: 'KhA'ng thапЯ gап-i email О`аз·t lазнi mаз-t khазcu.' }
  }

  return { success: true }
}

// Г"?Г"?Г"? Get current session user Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

export async function getCurrentUser() {
  const supabase = await createClient()

  const {
    data: { user },
    error,
  } = await supabase.auth.getUser()

  if (error || !user) return null

  type EmpRow = {
    id: string; full_name: string; role: string; position: string;
    branch_id: string | null; is_active: boolean
  }
  const empResult = await supabase
    .from('employees')
    .select('id, full_name, role, position, branch_id, is_active')
    .eq('id', user.id)
    .maybeSingle()

  const employee = empResult.data as EmpRow | null

  if (!employee) return null
  if (!employee.is_active) return null

  return {
    id: user.id,
    email: user.email ?? '',
    full_name: employee.full_name,
    role: employee.role,
    position: employee.position,
    branch_id: employee.branch_id,
  }
}

