'use server'

import { createClient } from '@/lib/supabase/server'
import { getCurrentUser } from '@/lib/actions/auth-actions'
import type { Branch, BranchInsert, BranchUpdate } from '@/lib/types/database'

export interface ActionResult<T = void> {
  success: boolean
  data?: T
  error?: string
}

// Г"?Г"?Г"? Get branches Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

/**
 * Get branches scoped by role:
 * - admin: all branches
 * - branch_manager: own branch only
 */
export async function getBranches(): Promise<ActionResult<Branch[]>> {
  try {
    const user = await getCurrentUser()
    if (!user) return { success: false, error: 'ChТ°a О`ОЯng nhаз-p.' }

    const supabase = await createClient()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const sb = supabase as any

    if (user.role === 'admin') {
      const { data, error } = await sb.from('branches').select('*').order('name')
      if (error) throw error
      return { success: true, data: (data ?? []) as Branch[] }
    }

    if (user.role === 'branch_manager' && user.branch_id) {
      const { data, error } = await sb
        .from('branches')
        .select('*')
        .eq('id', user.branch_id)
        .maybeSingle()
      if (error) throw error
      return { success: true, data: data ? [data as Branch] : [] }
    }

    return { success: false, error: 'Bазнn khA'ng cA3 quyап?n xem chi nhAнnh.' }
  } catch (err) {
    console.error('[getBranches]', err)
    return { success: false, error: 'KhA'ng thапЯ tазЬi danh sAнch chi nhAнnh.' }
  }
}

// Г"?Г"?Г"? Create branch Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?Г"?

/** Admin only: create a new branch */
export async function createBranch(
  data: BranchInsert
): Promise<ActionResult<Branch>> {
  try {
