13:export async function loginAction(
14:  email: string,
15:  password: string
16:): Promise<LoginResult> {
17:  const supabase = await createClient()
18:
19:  const { data, error } = await supabase.auth.signInWithPassword({
20:    email: email.trim().toLowerCase(),
21:    password,
22:  })
23:
24:  if (error) {
25:    // Return user-friendly Vietnamese messages
26:    if (error.message.includes('Invalid login credentials')) {
27:      return { success: false, error: 'Email hoặc mật khẩu không đúng.' }
28:    }
29:    if (error.message.includes('Email not confirmed')) {
30:      return { success: false, error: 'Email chưa được xác nhận.' }
31:    }
32:    return { success: false, error: 'Đăng nhập thất bại. Vui lòng thử lại.' }
33:  }
34:
35:  if (!data.user) {
36:    return { success: false, error: 'Không tìm thấy tài khoản.' }
37:  }
38:
39:  // Verify employee record exists and is active
40:  type EmployeeRow = { id: string; is_active: boolean; role: string }
41:  const empResult = await supabase
42:    .from('employees')
43:    .select('id, is_active, role')
44:    .eq('id', data.user.id)
45:    .maybeSingle()
46:
47:  const employee = empResult.data as EmployeeRow | null
48:
49:  if (empResult.error || !employee) {
50:    await supabase.auth.signOut()
51:    return { success: false, error: 'Tài khoản nhân viên không tồn tại.' }
52:  }
53:
54:  if (!employee.is_active) {
55:    await supabase.auth.signOut()
56:    return { success: false, error: 'Tài khoản đã bị vô hiệu hóa.' }
57:  }
58:
59:  redirect('/dashboard')
60:}
