37:// ─── Get employees ─────────────────────────────────────────────────────────────
38:
39:export async function getEmployees(
40:  branchId?: string
41:): Promise<ActionResult<EmployeeWithBranch[]>> {
42:  try {
43:    const user = await getCurrentUser()
44:    if (!user) return { success: false, error: 'Chưa đăng nhập.' }
45:
46:    const canView = user.role === 'admin' || user.role === 'branch_manager'
47:    if (!canView) return { success: false, error: 'Bạn không có quyền xem nhân viên.' }
48:
49:    const supabase = await createClient()
50:    // eslint-disable-next-line @typescript-eslint/no-explicit-any
51:    const sb = supabase as any
52:
53:    let query = sb.from('employees').select('*, branches(name)').order('full_name')
54:
55:    if (user.role === 'branch_manager' && user.branch_id) {
56:      query = query.eq('branch_id', user.branch_id)
57:    } else if (branchId) {
58:      query = query.eq('branch_id', branchId)
59:    }
60:
61:    const { data, error } = await query
62:    if (error) throw error
63:
64:    const employees: EmployeeWithBranch[] = ((data as unknown[]) ?? []).map((emp) => {
65:      const e = emp as Employee & { branches: { name: string } | null }
66:      const { branches, ...rest } = e
67:      return { ...rest, branch_name: branches?.name ?? null }
68:    })
69:
70:    return { success: true, data: employees }
71:  } catch (err) {
72:    console.error('[getEmployees]', err)
73:    return { success: false, error: 'Không thể tải danh sách nhân viên.' }
74:  }
75:}
