84:    if (!user) return { success: false, error: 'Chưa đăng nhập.' }
85:
86:    const supabase = await createClient()
87:    // eslint-disable-next-line @typescript-eslint/no-explicit-any
88:    const sb = supabase as any
89:    const { data, error } = await sb
90:      .from('employees')
91:      .select('*, branches(name)')
92:      .eq('id', id)
93:      .maybeSingle()
94:
95:    if (error) throw error
96:    if (!data) return { success: false, error: 'Không tìm thấy nhân viên.' }
97:
98:    const emp = data as Employee & { branches: { name: string } | null }
99:
100:    if (user.role === 'branch_manager' && emp.branch_id !== user.branch_id) {
101:      return { success: false, error: 'Bạn không có quyền xem nhân viên này.' }
102:    }
103:
104:    const { branches, ...rest } = emp
105:    return { success: true, data: { ...rest, branch_name: emp.branches?.name ?? null } }
106:  } catch (err) {
107:    console.error('[getEmployeeById]', err)
108:    return { success: false, error: 'Không thể tải thông tin nhân viên.' }
109:  }
110:}
