112:// ─── Create employee ──────────────────────────────────────────────────────────
113:
114:export async function createEmployee(
115:  input: CreateEmployeeInput
116:): Promise<ActionResult<Employee>> {
117:  try {
118:    const user = await getCurrentUser()
119:    if (!user) return { success: false, error: 'Chưa đăng nhập.' }
120:
121:    const canCreate = user.role === 'admin' || user.role === 'branch_manager'
122:    if (!canCreate) return { success: false, error: 'Bạn không có quyền tạo nhân viên.' }
123:
124:    const branchId = user.role === 'branch_manager' ? user.branch_id : (input.branch_id ?? null)
125:
126:    // 1. Create auth user with role + branch in app_metadata
127:    const authUser = await createAuthUser({
128:      email: input.email,
129:      password: input.password,
130:      role: input.role,
131:      branchId: branchId ?? undefined,
132:    })
133:
134:    // 2. Insert employee record (id = auth.users.id)
135:    const supabase = await createClient()
136:    // eslint-disable-next-line @typescript-eslint/no-explicit-any
137:    const sb = supabase as any
138:
139:    const { data: employee, error } = await sb.from('employees').insert({
140:      id: authUser.id,
141:      employee_code: input.employee_code,
142:      full_name: input.full_name,
143:      email: input.email,
144:      phone: input.phone ?? null,
145:      position: input.position,
146:      role: input.role,
147:      branch_id: branchId,
148:      rate_per_session: input.rate_per_session,
149:      sub_rate: input.sub_rate ?? 0,
150:      has_labor_contract: input.has_labor_contract,
151:      dependent_count: input.dependent_count,
152:      is_active: true,
153:      join_date: new Date().toISOString().split('T')[0],
154:    }).select().single()
155:
156:    if (error) throw error
157:    return { success: true, data: employee as Employee }
158:  } catch (err: unknown) {
159:    console.error('[createEmployee]', err)
160:    const msg = err instanceof Error ? err.message : ''
161:    if (msg.includes('already registered') || msg.includes('already been registered')) {
162:      return { success: false, error: 'Email đã tồn tại trong hệ thống.' }
163:    }
164:    return { success: false, error: 'Không thể tạo nhân viên.' }
165:  }
166:}
