15:/**
16: * Get branches scoped by role:
17: * - admin: all branches
18: * - branch_manager: own branch only
19: */
20:export async function getBranches(): Promise<ActionResult<Branch[]>> {
21:  try {
22:    const user = await getCurrentUser()
23:    if (!user) return { success: false, error: 'Chưa đăng nhập.' }
24:
25:    const supabase = await createClient()
26:    // eslint-disable-next-line @typescript-eslint/no-explicit-any
27:    const sb = supabase as any
28:
29:    if (user.role === 'admin') {
30:      const { data, error } = await sb.from('branches').select('*').order('name')
31:      if (error) throw error
32:      return { success: true, data: (data ?? []) as Branch[] }
33:    }
34:
35:    if (user.role === 'branch_manager' && user.branch_id) {
36:      const { data, error } = await sb
37:        .from('branches')
38:        .select('*')
39:        .eq('id', user.branch_id)
40:        .maybeSingle()
41:      if (error) throw error
42:      return { success: true, data: data ? [data as Branch] : [] }
43:    }
44:
45:    return { success: false, error: 'Bạn không có quyền xem chi nhánh.' }
46:  } catch (err) {
47:    console.error('[getBranches]', err)
48:    return { success: false, error: 'Không thể tải danh sách chi nhánh.' }
49:  }
50:}
