62:    }
63:
64:    const supabase = await createClient()
65:    // eslint-disable-next-line @typescript-eslint/no-explicit-any
66:    const sb = supabase as any
67:    const { data: branch, error } = await sb
68:      .from('branches')
69:      .insert(data)
70:      .select()
71:      .single()
72:
73:    if (error) throw error
74:    return { success: true, data: branch as Branch }
75:  } catch (err) {
76:    console.error('[createBranch]', err)
